import React, { useState, useEffect, useContext } from 'react';
import Navbar from '../../components/common/Navbar';
import Sidebar from '../../components/common/Sidebar';
import Loader from '../../components/common/Loader';
import { ThemeContext } from '../../context/ThemeContext';
import { mockTopicPerformance } from '../../data/mockData';

const TopicPerformance = () => {
  const userName = localStorage.getItem('userName') || 'Student';
  const [loading, setLoading] = useState(true);
  const [topics, setTopics] = useState([]);
  const { isDark } = useContext(ThemeContext);

  useEffect(() => {
    fetchTopicPerformance();
  }, []);

  const fetchTopicPerformance = async () => {
    try {
      setTimeout(() => {
        setTopics(mockTopicPerformance.topics || []);
        setLoading(false);
      }, 500);
    } catch (error) {
      console.error('Error fetching topic performance:', error);
      setTopics([]);
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen galaxy-bg">
        <Navbar role="Student" userName={userName} />
        <div className="flex">
          <Sidebar role="student" />
          <main className="flex-1">
            <Loader />
          </main>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen galaxy-bg">
      <Navbar role="Student" userName={userName} />
      <div className="flex">
        <Sidebar role="student" />
        <main className="flex-1 p-6">
          <h2 className="text-3xl font-bold text-white mb-6">Topic Performance 📚</h2>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {topics.length > 0 ? (
              topics.map((topic, index) => (
                <div key={index} className="glass-card rounded-xl shadow-lg p-6 hover:shadow-2xl transition transform hover:scale-105">
                  <div className="flex justify-between items-start mb-4">
                    <h3 className="text-xl font-bold text-white">{topic.name}</h3>
                    <span className="text-2xl">{topic.trendIcon}</span>
                  </div>

                  <div className="space-y-3">
                    <div className="flex justify-between">
                      <span className="text-gray-300">Attempts</span>
                      <span className="font-semibold text-white">{topic.attempts}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-gray-300">Accuracy</span>
                      <span className={`font-semibold ${
                        topic.accuracy >= 80 ? 'text-green-400' : 
                        topic.accuracy >= 70 ? 'text-yellow-400' : 
                        'text-red-400'
                      }`}>
                        {topic.accuracy}%
                      </span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-gray-300">Avg Time</span>
                      <span className="font-semibold text-white">{topic.avgTime}</span>
                    </div>
                    <div className="flex justify-between items-center pt-2 border-t border-gray-600">
                      <span className="text-gray-300">Trend</span>
                      <span className={`font-semibold px-3 py-1 rounded-full text-sm ${
                        topic.color === 'green' ? 'bg-green-600 text-white' :
                        topic.color === 'blue' ? 'bg-blue-600 text-white' :
                        'bg-red-600 text-white'
                      }`}>
                        {topic.trend}
                      </span>
                    </div>
                  </div>
                </div>
              ))
            ) : (
              <div className="col-span-3 text-center text-gray-400 py-12">
                No topic performance data available yet
              </div>
            )}
          </div>
        </main>
      </div>
    </div>
  );
};

export default TopicPerformance;
